changeSet.sql:
GRANT USAGE ON SCHEMA taskforge TO ${app-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA taskforge GRANT USAGE ON SEQUENCES TO ${app-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA taskforge GRANT EXECUTE ON FUNCTIONS TO ${app-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA taskforge GRANT SELECT,INSERT,UPDATE ON TABLES TO ${app-username};

GRANT USAGE ON SCHEMA taskforge TO ${viewer-username};
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA taskforge TO ${viewer-username};
GRANT SELECT ON ALL TABLES IN SCHEMA taskforge TO ${viewer-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA taskforge GRANT EXECUTE ON FUNCTIONS TO ${viewer-username};
ALTER DEFAULT PRIVILEGES IN SCHEMA taskforge GRANT SELECT ON TABLES TO ${viewer-username};
